model User {
  id           Int           @id @default(autoincrement())
  email        String        @unique
  name         String?
  userProjects UserProject[]
}

model Project {
  id           Int           @id @default(autoincrement())
  name         String
  userProjects UserProject[]
}

model UserProject {
  userId    Int
  projectId Int
  role      String
  user      User    @relation(fields: [userId], references: [id])
  project   Project @relation(fields: [projectId], references: [id])

  @@id([userId, projectId])
}

